//! The `show-session` subcommand: display a Claude Code session
//! transcript (`.jsonl`) as a readable conversation.
//!
//! Default view renders the dialogue — user prompts and assistant
//! text in full, tool calls as one-liners — and hides thinking,
//! tool results, meta/system/sidechain lines, and bookkeeping
//! entry types. Reveal flags: `--thinking`, `--tools`, `--meta`.
//! A trailing summary line always reports what was hidden or
//! skipped. Malformed lines (e.g. a live session's truncated
//! last line) warn to stderr and never fail the run.

use std::path::PathBuf;

use clap::Args;
use log::{debug, info, warn};
use serde_json::Value;

use crate::common::bold;
use crate::context::Context;
use crate::subcommand::SubcommandRunner;
use crate::transcript::{self, ContentBlock, EntryKind, FileTranscript};

/// Max lines of one tool result shown under `--tools`.
const RESULT_LINE_CAP: usize = 10;

/// Max chars of a tool-use one-liner gist.
const GIST_CHAR_CAP: usize = 100;

/// Clap-derived args for `show-session`.
#[derive(Args, Debug)]
pub struct ShowSessionArgs {
    /// Session transcript .jsonl file to display
    #[arg(value_name = "FILE")]
    pub file: PathBuf,

    /// Show thinking blocks
    #[arg(long)]
    pub thinking: bool,

    /// Show tool results (truncated) under each tool call
    #[arg(long)]
    pub tools: bool,

    /// Show meta/system/sidechain entries
    #[arg(long)]
    pub meta: bool,
}

/// What the conversation view reveals beyond the default.
#[derive(Default)]
pub struct RenderOptions {
    /// Render thinking blocks.
    pub thinking: bool,
    /// Render tool results.
    pub tools: bool,
    /// Render meta/system/sidechain entries.
    pub meta: bool,
}

/// Inputs to the show-session op, flat, owned, clap-free.
pub struct ShowSessionParams {
    /// Transcript file to display.
    pub file: PathBuf,
    /// Reveal options for the renderer.
    pub opts: RenderOptions,
}

impl From<&ShowSessionArgs> for ShowSessionParams {
    /// Convert clap-derived `ShowSessionArgs` into the flat
    /// `ShowSessionParams` (total).
    fn from(a: &ShowSessionArgs) -> Self {
        Self {
            file: a.file.clone(),
            opts: RenderOptions {
                thinking: a.thinking,
                tools: a.tools,
                meta: a.meta,
            },
        }
    }
}

impl SubcommandRunner for ShowSessionArgs {
    type Params = ShowSessionParams;

    /// Delegate to the `From<&ShowSessionArgs>` impl (total).
    fn to_params(&self) -> Result<Self::Params, String> {
        Ok(ShowSessionParams::from(self))
    }

    /// Run the `show_session` op.
    fn run(ctx: &Context, params: &Self::Params) -> Result<(), Box<dyn std::error::Error>> {
