fn cli_version_runs() {
    let fx = CliFixture::new("smoke-version");
    let out = run_ok(fx.cmd().arg("--version"));
    let stdout = String::from_utf8_lossy(&out.stdout);
    assert!(
        stdout.contains("vc-x1"),
        "expected --version output to mention 'vc-x1', got: {stdout:?}"
    );
}

