fn cli_help_lists_init() {
    let fx = CliFixture::new("smoke-help");
    let out = run_ok(fx.cmd().arg("--help"));
    let stdout = String::from_utf8_lossy(&out.stdout);
    assert!(
        stdout.contains("init"),
        "expected --help to list 'init' subcommand, got: {stdout:?}"
    );
}

