fn render(t: &FileTranscript, opts: &RenderOptions) -> (Vec<String>, RenderStats) {
    let mut lines: Vec<String> = Vec::new();
    let mut stats = RenderStats::default();
    let mut turn: Option<TurnKey> = None;

    for e in &t.entries {
        if e.meta.is_sidechain && !opts.meta {
            stats.hidden_meta += 1;
            continue;
        }
        let time = short_time(e.meta.timestamp.as_deref());
        match &e.kind {
            EntryKind::User {
                content,
                prompt_source: _,
            } => {
                if e.meta.is_meta && !opts.meta {
                    stats.hidden_meta += 1;
                    continue;
                }
                let label = if e.meta.is_meta {
                    "user (meta)"
                } else {
                    "user"
                };
                for b in content {
                    match b {
                        ContentBlock::Text { text } => {
                            if !text.trim().is_empty() {
                                header(
                                    &mut lines, &mut stats, &mut turn, label, None, &time,
                                    opts.color,
                                );
                                lines.extend(text.lines().map(str::to_string));
                            }
                        }
                        ContentBlock::ToolResult { text, is_error, .. } => {
                            if opts.tools {
                                push_result(&mut lines, text, *is_error);
                            } else {
                                stats.hidden_tool_results += 1;
                            }
                        }
                        _ => {}
                    }
                }
            }
            EntryKind::Assistant {
                content,
                message_id,
            } => {
                for b in content {
                    match b {
                        ContentBlock::Text { text } => {
                            if !text.trim().is_empty() {
                                header(
                                    &mut lines,
                                    &mut stats,
                                    &mut turn,
                                    "assistant",
                                    message_id.as_deref(),
                                    &time,
                                    opts.color,
                                );
                                lines.extend(text.lines().map(str::to_string));
                            }
                        }
                        ContentBlock::ToolUse { name, input, .. } => {
                            header(
                                &mut lines,
                                &mut stats,
                                &mut turn,
                                "assistant",
                                message_id.as_deref(),
                                &time,
                                opts.color,
                            );
                            lines.push(format!("  [tool] {}", tool_use_gist(name, input)));
                        }
                        ContentBlock::Thinking { thinking } => {
                            if thinking.trim().is_empty() {
                                continue;
                            }
                            if opts.thinking {
                                header(
                                    &mut lines,
                                    &mut stats,
                                    &mut turn,
                                    "assistant",
                                    message_id.as_deref(),
                                    &time,
                                    opts.color,
                                );
                                lines.push("  [thinking]".to_string());
                                lines.extend(thinking.lines().map(|l| format!("  {l}")));
                            } else {
                                stats.hidden_thinking += 1;
                            }
                        }
                        _ => {}

